// Prefrontal POSTs outbound events here (N8N_WEBHOOK_URL). This workflow only
// acts on triage.urgent — the nudge triage.apply() fires when a signal is
// urgent (overdue/imminent). Emit one ntfy-ready item, or nothing for other
// events (episode.logged, reminder.sent, …), which your other flows handle.
const b = $input.first().json.body || $input.first().json;
if (!b || b.event !== 'triage.urgent') return [];
const where = b.routed_ref ? ` → ${b.routed_ref}` : '';
return [{ json: {
  title: 'Prefrontal — urgent',
  message: `${b.title || 'Something needs attention'} (${b.kind || 'action'})${where}`,
} }];
